 1	import React, { FC } from 'react';
 2	
 3	import ExternalLink from '@kubevirt-utils/components/ExternalLink/ExternalLink';
 4	import FormGroupHelperText from '@kubevirt-utils/components/FormGroupHelperText/FormGroupHelperText';
 5	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { FormGroup, NumberInput, Text, TextInput, Title } from '@patternfly/react-core';
 8	
 9	import { AddBootableVolumeState, SetBootableVolumeFieldType } from '../utils/constants';
10	
11	type SchedulingSettingsProps = {
12	  bootableVolume: AddBootableVolumeState;
13	  setBootableVolumeField: SetBootableVolumeFieldType;
14	};
15	
16	const SchedulingSettings: FC<SchedulingSettingsProps> = ({
17	  bootableVolume,
18	  setBootableVolumeField,
19	}) => {
20	  const { t } = useKubevirtTranslation();
21	
22	  const { cronExpression, retainRevisions } = bootableVolume || {};
23	
24	  return (
25	    <>
26	      <FormGroup
27	        fieldId="volume-registry-retain-revisions"
28	        isRequired
29	        label={t('Retain revisions')}
30	      >
31	        <NumberInput
32	          onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
33	            setBootableVolumeField('retainRevisions')(event.currentTarget.valueAsNumber)
34	          }
35	          id="volume-registry-retain-revisions"
36	          min={0}
37	          minusBtnAriaLabel={t('Decrement')}
38	          onMinus={() => setBootableVolumeField('retainRevisions')(retainRevisions - 1)}
39	          onPlus={() => setBootableVolumeField('retainRevisions')(retainRevisions + 1)}
40	          plusBtnAriaLabel={t('Increment')}
41	          value={retainRevisions}
42	        />
43	        <FormGroupHelperText>
44	          {t(
45	            'Specify the number of revisions that should be retained. A value of X means that the X latest versions will be kept.',
46	          )}
47	        </FormGroupHelperText>
48	      </FormGroup>
49	      <div>
50	        <Title headingLevel="h2" size="md">
51	          {t('Scheduling settings')}
52	        </Title>
53	        <Text>
54	          {t('Use cron formatting to set when and how often to look for new imports.')}{' '}
55	          <ExternalLink href={documentationURL.CRON_INFO} text={t('Learn more')} />
56	        </Text>
57	      </div>
58	      <FormGroup
59	        fieldId="volume-registry-retain-cron-expression"
60	        isRequired
61	        label={t('Cron expression')}
62	      >
63	        <TextInput
64	          data-test-id="volume-registry-retain-cron-expression"
65	          id="volume-registry-retain-cron-expression"
66	          onChange={(_, value: string) => setBootableVolumeField('cronExpression')(value)}
67	          type="text"
68	          value={cronExpression}
69	        />
70	        <FormGroupHelperText>{t('Example (At 00:00 on Tuesday): 0 0 * * 2.')}</FormGroupHelperText>
71	      </FormGroup>
72	    </>
73	  );
74	};
75	
76	export default SchedulingSettings;

